```class Solution {
    public long waysToBuyPensPencils(int total, int cost1, int cost2) {
        long ways = 0;
        for (int pens = 0; pens * cost1 <= total; pens++) {
            int pencils = total - pens * cost1;
            ways += waysToBuyPencils(pencils, cost2);
        }
        return ways;
    }
    public int waysToBuyPencils(int total, int cost) {
        if (total < 0) return 0;
        if (total == 0) return 1;
        int ways = 0;
        for (int pencils = 0; pencils * cost <= total; pencils++) {
            ways += waysToBuyPencils(total - pencils * cost, cost);
        }
        return ways;
    }
}``
